import React from "react";

const skills = [
  {
    title: "Electrical Basics",
    icon: "⚡",
    items: ["Circuit understanding", "Wiring basics", "System thinking"],
  },
  {
    title: "Project Work",
    icon: "🛠",
    items: ["Problem solving", "Hands-on learning", "Project planning"],
  },
  {
    title: "Team Skills",
    icon: "🤝",
    items: ["Communication", "Collaboration", "Documentation"],
  },
  {
    title: "Tools & Mindset",
    icon: "🔧",
    items: ["Quick learner", "Practical approach", "Attention to detail"],
  },
];

function Skills() {
  return (
    <div className="section-shell">
      <div className="section-heading">
        <p className="eyebrow">🧠 Skills</p>
        <h2>What I’m comfortable with</h2>
      </div>

      <div className="skills-grid">
        {skills.map((skill) => (
          <article className="skill-card" key={skill.title}>
            <div className="skill-icon">{skill.icon}</div>
            <h3>{skill.title}</h3>
            <ul>
              {skill.items.map((item) => (
                <li key={item}>{item}</li>
              ))}
            </ul>
          </article>
        ))}
      </div>
    </div>
  );
}

export default Skills;
